package com.doc.entity.vendor;

import com.doc.entity.product.Product;
import jakarta.persistence.*;
import lombok.*;
import org.hibernate.annotations.Comment;

import java.util.ArrayList;
import java.util.Date;
import java.util.List;

/**
 * RFQ entity represents Request For Quotation.
 *
 * Example:
 * Corpseed creates RFQ for "50 Tons Cement + Steel Bars"
 * and sends it to multiple vendors like Balaji Traders, Shree Enterprises, RK Suppliers.
 */
@Entity
@Table(name = "rfqs", indexes = {
        @Index(name = "idx_rfq_number", columnList = "rfqNumber", unique = true),
        @Index(name = "idx_rfq_status", columnList = "status")
})
@Getter
@Setter
@NoArgsConstructor
@AllArgsConstructor
public class RFQ {

    /**
     * Primary key of RFQ table.
     */
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    /**
     * Unique RFQ number generated by system.
     *
     * Example:
     * RFQ-CDSO-0622
     * RFQ-2026-0001
     */
    @Column(nullable = false, unique = true, length = 100)
    @Comment("Unique RFQ Number like RFQ-2026-0001")
    private String rfqNumber;

    /**
     * Short title of RFQ.
     *
     * Example:
     * Cement and Steel Procurement
     */
    @Column(nullable = false, length = 255)
    private String title;

    /**
     * Detailed description of RFQ requirement.
     *
     * Example:
     * Need 50 Tons Cement and Steel Bars for CDSO Site Development Project.
     */
    @Column(length = 2000)
    private String description;

    /**
     * Product/Solution/Service for which RFQ is created.
     *
     * Example:
     * Construction Material, Website Development, Legal Service, etc.
     */
    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "product_id")
    private Product product;

    /**
     * Scope of work or requirement details.
     *
     * Example:
     * Vendor must supply 50 Tons Cement and Steel Bars at project site.
     */
    @Column(columnDefinition = "TEXT")
    private String scopeOfWork;

    /**
     * Terms and conditions shared with vendors.
     *
     * Example:
     * Delivery terms, payment terms, penalty clause, warranty terms.
     */
    @Column(columnDefinition = "TEXT")
    private String termsAndConditions;

    /**
     * Delivery or work execution location.
     *
     * Example:
     * CDSO Site, Noida, Uttar Pradesh.
     */
    @Column(length = 500)
    private String deliveryLocation;

    /**
     * Last date for vendors to submit quotation.
     *
     * Example:
     * Vendor must submit quotation before 25-June-2026.
     */
    @Temporal(TemporalType.DATE)
    private Date quotationSubmissionDeadline;

    /**
     * Expected start date of work/material supply.
     */
    @Temporal(TemporalType.DATE)
    private Date expectedStartDate;

    /**
     * Expected end date or delivery completion date.
     */
    @Temporal(TemporalType.DATE)
    private Date expectedEndDate;

    /**
     * Internal procurement contact person name.
     *
     * Example:
     * Person who handles vendor communication for this RFQ.
     */
    @Column(length = 255)
    private String contactPersonName;

    /**
     * Internal procurement contact person email.
     */
    @Column(length = 255)
    private String contactPersonEmail;

    /**
     * Internal procurement contact person mobile number.
     */
    @Column(length = 20)
    private String contactPersonMobile;

    /**
     * Overall RFQ status.
     *
     * Important:
     * This is RFQ-level status, not vendor-wise status.
     *
     * Example:
     * If RFQ is sent to 3 vendors, RFQ status becomes SENT.
     * Vendor-wise status will be maintained in RFQVendor entity.
     */
    @Enumerated(EnumType.STRING)
    @Column(nullable = false, length = 50)
    private RFQStatus status = RFQStatus.DRAFT;

    /**
     * RFQ attachment URL.
     *
     * Example:
     * PDF, Excel, BOQ, specification file, scope document.
     */
    @Column(length = 500)
    private String attachmentUrl;

    /**
     * Record creation date and time.
     */
    @Temporal(TemporalType.TIMESTAMP)
    private Date createdDate;

    /**
     * Last record update date and time.
     */
    @Temporal(TemporalType.TIMESTAMP)
    private Date updatedDate;

    /**
     * User ID who created this RFQ.
     */
    private Long createdBy;

    /**
     * User ID who last updated this RFQ.
     */
    private Long updatedBy;

    /**
     * Soft delete flag.
     *
     * false = active record
     * true = deleted record
     */
    private boolean isDeleted = false;

    /**
     * Vendors added/sent under this RFQ.
     *
     * One RFQ can be sent to multiple vendors.
     *
     * Example:
     * RFQ-CDSO-0622
     *      -> Balaji Traders
     *      -> Shree Enterprises
     *      -> RK Suppliers
     *
     * Vendor-wise status is maintained in RFQVendor.
     */
    @OneToMany(mappedBy = "rfq", cascade = CascadeType.ALL, orphanRemoval = true)
    private List<RFQVendor> vendors = new ArrayList<>();

    /**
     * Automatically called before inserting record into database.
     * Sets createdDate and updatedDate.
     */
    @PrePersist
    public void onCreate() {
        this.createdDate = new Date();
        this.updatedDate = new Date();
    }

    /**
     * Automatically called before updating record into database.
     * Updates updatedDate.
     */
    @PreUpdate
    public void onUpdate() {
        this.updatedDate = new Date();
    }
}